#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
using namespace std;
inline int read(){
    int x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(int x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
CI MAXN=1e6+5;
int t[MAXN],w[MAXN],f[MAXN],T,M;
int main(void){
	M=read();T=read();

    for(int i=1;i<=M;++i)t[i]=read(),w[i]=read();
    for(int i=1;i<=M;++i)
    {
    	for(int j=T;j>=t[i];--j)
        {
        	f[j]=max(f[j],f[j-t[i]]+w[i]);
		}
	}
	write(f[T]);
    return false;
}
